#include <iostream>
#include <string>

template <typename T>
T findMax(T a, T b) {
    if (a > b) {
        return a;
    } else {
        return b;
    }
}

int main() {
    std::cout << findMax(5, 10) << std::endl;
    std::cout << findMax(15, 7) << std::endl;
    std::cout << findMax(8, 8) << std::endl;
    std::cout << findMax(3.14, 2.71) << std::endl;
    std::cout << findMax(1.0, 2.0) << std::endl;
    std::cout << findMax('a', 'z') << std::endl;
    std::cout << findMax('X', 'B') << std::endl;
    std::cout << findMax(std::string("apple"), std::string("banana")) << std::endl;
    return 0;
}
